import java.util.Scanner;
import java.nio.ByteBuffer;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Using ByteBuffer to handle buffer safely
        ByteBuffer buffer = ByteBuffer.allocate(10);
        buffer.put(name.getBytes(), 0, Math.min(name.length(), buffer.capacity()));

        // Reset position to read from the beginning
        buffer.flip();

        // Create a byte array with correct size to get the data
        byte[] resultBytes = new byte[buffer.remaining()];
        buffer.get(resultBytes);

        System.out.println("Hello, " + new String(resultBytes));
    }
}

### Explanation:
취약유형: Buffer Overflow
